/**
 * Progress Persistence
 *
 * Manages progress.txt and features.json for session memory.
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync } from 'fs';
import { join } from 'path';

export interface Feature {
  id: string;
  title: string;
  description: string;
  status: 'pending' | 'in_progress' | 'complete' | 'blocked';
  dependencies: string[];
  acceptanceCriteria: string[];
  sessions: number;
  createdAt: string;
  updatedAt: string;
}

export interface FeaturesFile {
  version: string;
  projectName: string;
  features: Feature[];
}

const PROGRESS_TEMPLATE = `# Belt Harness Progress

This file tracks progress between sessions.
It is read by the harness to maintain context.

## Current Status

- Project initialized: {{date}}
- Features defined: 0
- Sessions completed: 0

## Session History

<!-- Sessions will be logged here -->

## Notes

<!-- Add notes for future sessions -->
`;

const FEATURES_TEMPLATE: FeaturesFile = {
  version: '1.0.0',
  projectName: '',
  features: [],
};

/**
 * Initialize .belt directory structure.
 */
export function initBeltDirectory(projectDir: string): void {
  const beltDir = join(projectDir, '.belt');
  const harnessDir = join(beltDir, 'harness');
  const rollbackDir = join(harnessDir, 'rollback');
  const configDir = join(beltDir, 'config');
  const tempDir = join(beltDir, 'temp');

  const dirs = [
    beltDir,
    harnessDir,
    rollbackDir,
    configDir,
    tempDir,
  ];

  for (const dir of dirs) {
    if (!existsSync(dir)) {
      mkdirSync(dir, { recursive: true });
    }
  }

  // Create .gitignore for temp
  const gitignorePath = join(beltDir, '.gitignore');
  if (!existsSync(gitignorePath)) {
    writeFileSync(gitignorePath, 'temp/\n');
  }
}

/**
 * Create or get progress.txt file.
 */
export function createProgressFile(projectDir: string): string {
  const progressPath = join(projectDir, '.belt', 'harness', 'progress.txt');

  if (!existsSync(progressPath)) {
    const content = PROGRESS_TEMPLATE.replace(
      '{{date}}',
      new Date().toISOString().split('T')[0],
    );
    writeFileSync(progressPath, content);
  }

  return progressPath;
}

/**
 * Read progress.txt content.
 */
export function readProgress(projectDir: string): string {
  const progressPath = join(projectDir, '.belt', 'harness', 'progress.txt');

  if (!existsSync(progressPath)) {
    return '';
  }

  return readFileSync(progressPath, 'utf-8');
}

/**
 * Append to progress.txt.
 */
export function appendProgress(projectDir: string, content: string): void {
  const progressPath = join(projectDir, '.belt', 'harness', 'progress.txt');
  const existing = existsSync(progressPath)
    ? readFileSync(progressPath, 'utf-8')
    : '';
  writeFileSync(progressPath, existing + '\n' + content);
}

/**
 * Create or get features.json file.
 */
export function createFeaturesFile(
  projectDir: string,
  projectName = '',
): string {
  const featuresPath = join(projectDir, '.belt', 'harness', 'features.json');

  if (!existsSync(featuresPath)) {
    const content = {
      ...FEATURES_TEMPLATE,
      projectName,
    };
    writeFileSync(featuresPath, JSON.stringify(content, null, 2));
  }

  return featuresPath;
}

/**
 * Read features.json content.
 */
export function readFeatures(projectDir: string): FeaturesFile {
  const featuresPath = join(projectDir, '.belt', 'harness', 'features.json');

  if (!existsSync(featuresPath)) {
    return { ...FEATURES_TEMPLATE };
  }

  return JSON.parse(readFileSync(featuresPath, 'utf-8'));
}

/**
 * Write features.json content.
 */
export function writeFeatures(
  projectDir: string,
  features: FeaturesFile,
): void {
  const featuresPath = join(projectDir, '.belt', 'harness', 'features.json');
  writeFileSync(featuresPath, JSON.stringify(features, null, 2));
}

/**
 * Add a feature to features.json.
 */
export function addFeature(
  projectDir: string,
  feature: Omit<Feature, 'createdAt' | 'updatedAt'>,
): void {
  const features = readFeatures(projectDir);
  const now = new Date().toISOString();

  features.features.push({
    ...feature,
    createdAt: now,
    updatedAt: now,
  });

  writeFeatures(projectDir, features);
}

/**
 * Update a feature status.
 */
export function updateFeatureStatus(
  projectDir: string,
  featureId: string,
  status: Feature['status'],
): void {
  const features = readFeatures(projectDir);
  const feature = features.features.find(f => f.id === featureId);

  if (feature) {
    feature.status = status;
    feature.updatedAt = new Date().toISOString();
    writeFeatures(projectDir, features);
  }
}

/**
 * Brainstorm session state for persistence
 */
export interface BrainstormSessionState {
  sessionId: string;
  phase: string;
  startedAt: string;
  updatedAt: string;
  context: Record<string, unknown> | null;
  rawFeaturesCount: number;
  refinedFeaturesCount: number;
  errors: string[];
  completed: boolean;
}

/**
 * Save brainstorm session state
 */
export function saveBrainstormState(
  projectDir: string,
  state: BrainstormSessionState,
): void {
  const statePath = join(
    projectDir,
    '.belt',
    'harness',
    'brainstorm-state.json',
  );
  writeFileSync(statePath, JSON.stringify(state, null, 2));
}

/**
 * Load brainstorm session state
 */
export function loadBrainstormState(
  projectDir: string,
): BrainstormSessionState | null {
  const statePath = join(
    projectDir,
    '.belt',
    'harness',
    'brainstorm-state.json',
  );

  if (!existsSync(statePath)) {
    return null;
  }

  try {
    return JSON.parse(readFileSync(statePath, 'utf-8'));
  } catch {
    return null;
  }
}

/**
 * Backlog feature structure for persistence
 */
export interface BacklogFeature {
  id: string;
  title: string;
  description: string;
  acceptanceCriteria: string[];
  dependencies?: string[];
  priority: string;
  epic?: string;
  refinementIterations?: number;
}

/**
 * Backlog structure for persistence
 */
export interface PersistedBacklog {
  projectName: string;
  createdAt: string;
  epics: Array<{
    id: string;
    name: string;
    description: string;
    featureIds: string[];
  }>;
  features: BacklogFeature[];
}

/**
 * Save brainstorm backlog result
 */
export function saveBrainstormBacklog(
  projectDir: string,
  backlog: PersistedBacklog,
): void {
  const backlogPath = join(projectDir, '.belt', 'harness', 'backlog.json');
  writeFileSync(backlogPath, JSON.stringify(backlog, null, 2));

  // Also update features.json with the features from backlog
  const featuresFile = readFeatures(projectDir);
  const backlogFeatures = backlog.features || [];

  for (const bf of backlogFeatures) {
    // Check if feature already exists
    const existing = featuresFile.features.find(f => f.id === bf.id);
    if (!existing) {
      const now = new Date().toISOString();
      featuresFile.features.push({
        id: bf.id,
        title: bf.title,
        description: bf.description,
        status: 'pending',
        dependencies: bf.dependencies || [],
        acceptanceCriteria: bf.acceptanceCriteria || [],
        sessions: 0,
        createdAt: now,
        updatedAt: now,
      });
    }
  }

  featuresFile.projectName = backlog.projectName || featuresFile.projectName;
  writeFeatures(projectDir, featuresFile);
}

/**
 * Load brainstorm backlog
 */
export function loadBrainstormBacklog(
  projectDir: string,
): PersistedBacklog | null {
  const backlogPath = join(projectDir, '.belt', 'harness', 'backlog.json');

  if (!existsSync(backlogPath)) {
    return null;
  }

  try {
    return JSON.parse(readFileSync(backlogPath, 'utf-8'));
  } catch {
    return null;
  }
}

/**
 * Log session entry to progress.txt
 */
export function logSession(
  projectDir: string,
  summary: {
    sessionId: string;
    duration: number;
    featuresGenerated: number;
    featuresApproved: number;
    phase: string;
    errors: string[];
  },
): void {
  const timestamp = new Date().toISOString();
  const entry = `
### Session ${summary.sessionId}
- **Date:** ${timestamp}
- **Duration:** ${(summary.duration / 1000).toFixed(1)}s
- **Phase reached:** ${summary.phase}
- **Features generated:** ${summary.featuresGenerated}
- **Features approved:** ${summary.featuresApproved}
${summary.errors.length > 0 ? `- **Errors:** ${summary.errors.join(', ')}` : ''}
`;

  appendProgress(projectDir, entry);
}

/**
 * Create session rollback snapshot
 */
export function createRollbackSnapshot(
  projectDir: string,
  sessionId: string,
): void {
  const harnessDir = join(projectDir, '.belt', 'harness');
  const rollbackDir = join(harnessDir, 'rollback', `session-${sessionId}`);

  if (!existsSync(rollbackDir)) {
    mkdirSync(rollbackDir, { recursive: true });
  }

  // Copy current state files
  const filesToBackup = [
    'features.json',
    'backlog.json',
    'brainstorm-state.json',
  ];

  for (const file of filesToBackup) {
    const sourcePath = join(harnessDir, file);
    if (existsSync(sourcePath)) {
      const content = readFileSync(sourcePath, 'utf-8');
      writeFileSync(join(rollbackDir, file), content);
    }
  }
}

/**
 * Restore from rollback snapshot
 */
export function restoreRollbackSnapshot(
  projectDir: string,
  sessionId: string,
): boolean {
  const harnessDir = join(projectDir, '.belt', 'harness');
  const rollbackDir = join(harnessDir, 'rollback', `session-${sessionId}`);

  if (!existsSync(rollbackDir)) {
    return false;
  }

  const filesToRestore = [
    'features.json',
    'backlog.json',
    'brainstorm-state.json',
  ];

  for (const file of filesToRestore) {
    const sourcePath = join(rollbackDir, file);
    if (existsSync(sourcePath)) {
      const content = readFileSync(sourcePath, 'utf-8');
      writeFileSync(join(harnessDir, file), content);
    }
  }

