import type { BeltContext, BeltPlugin, CheckResult } from '@belt/core';

export interface MyPluginOptions {
  enabled?: boolean;
}

export function myPlugin(options: MyPluginOptions = {}): BeltPlugin {
  const { enabled = true } = options;

  return {
    name: 'my-plugin',
    apply(belt) {
      if (!enabled) return;

      // Initialize plugin
      belt.hooks.initialize.tapPromise('my-plugin', async (ctx: BeltContext) => {
        ctx.log('info', '[my-plugin] Initialized');
      });

      // Run before checks
      belt.hooks.beforeCheck.tapPromise('my-plugin', async (_ctx: BeltContext) => {
        // Pre-check logic
      });

      // Process check results
      belt.hooks.checkResults.tapPromise(
        'my-plugin',
        async (_ctx: BeltContext, results: CheckResult[]) => {
          // Add custom results
          const customResults: CheckResult[] = [];

          return [...results, ...customResults];
        },
      );

      // Cleanup
      belt.hooks.shutdown.tapPromise('my-plugin', async (_ctx: BeltContext) => {
        // Cleanup logic
      });
    },
  };
}

