  ...fns: readonly ((...args: unknown[]) => unknown)[]
): unknown {
  if (fns.length === 0) {
    return <T>(arg: T): T => arg;
  }

  if (fns.length === 1) {
    return fns[0];
  }

  return fns.reduce(
    (a, b) =>
      (...args: unknown[]) =>
        a(b(...args)),
