import { describe, expect, it } from 'vitest';
import { compose } from '../compose';

describe('compose', () => {
  describe('with no functions', () => {
    it('should return identity function', () => {
      const identity = compose();
      expect(identity(5)).toBe(5);
      expect(identity('hello')).toBe('hello');
      expect(identity({ a: 1 })).toEqual({ a: 1 });
    });
  });

  describe('with single function', () => {
    it('should return the same function', () => {
      const double = (x: number) => x * 2;
      const composed = compose(double);
      expect(composed(5)).toBe(10);
    });
  });

  describe('with two functions', () => {
    it('should compose right to left', () => {
      const add1 = (x: number) => x + 1;
      const double = (x: number) => x * 2;

      const composed = compose(double, add1);
      expect(composed(5)).toBe(12); // (5 + 1) * 2 = 12
    });

    it('should handle different return types', () => {
      const toString = (x: number) => `Value: ${x}`;
      const double = (x: number) => x * 2;

      const composed = compose(toString, double);
      expect(composed(5)).toBe('Value: 10');
    });
  });

