import { describe, expect, it, vi } from 'vitest';
import { InvariantError } from '../error-utils';
import {
  assertObject,
  assertValues,
  createObject,
  deepFreeze,
  flatRecordRecords,
  getProperty,
  isObject,
  keyBy,
  objectEntries,
  objectHasOwnProperty,
  objectKeys,
  objectValues,
  reduceObject,
  requireAll,
  setProperties,
  setProperty,
} from '../object-utils';

describe('object-utils', () => {
  describe('objectKeys', () => {
    it('should return keys of an object', () => {
      const obj = { a: 1, b: 2, c: 3 };
      expect(objectKeys(obj)).toEqual(['a', 'b', 'c']);
    });

    it('should return empty array for empty object', () => {
      expect(objectKeys({})).toEqual([]);
    });

    it('should handle objects with various value types', () => {
      const obj = { str: 'hello', num: 42, bool: true, arr: [1, 2] };
      expect(objectKeys(obj)).toEqual(['str', 'num', 'bool', 'arr']);
    });
  });

  describe('objectEntries', () => {
    it('should return entries of an object', () => {
      const obj = { a: 1, b: 2 };
      expect(objectEntries(obj)).toEqual([
        ['a', 1],
        ['b', 2],
      ]);
    });

    it('should return empty array for empty object', () => {
      expect(objectEntries({})).toEqual([]);
    });
  });

  describe('objectValues', () => {
    it('should return values of an object', () => {
      const obj = { a: 1, b: 2, c: 3 };
      expect(objectValues(obj)).toEqual([1, 2, 3]);
    });

    it('should return empty array for empty object', () => {
      expect(objectValues({})).toEqual([]);
    });
  });

  describe('isObject', () => {
    it('should return true for plain objects', () => {
      expect(isObject({})).toBe(true);
      expect(isObject({ a: 1 })).toBe(true);
      expect(isObject(Object.create(null))).toBe(true);
    });

    it('should return false for arrays', () => {
      expect(isObject([])).toBe(false);
      expect(isObject([1, 2, 3])).toBe(false);
    });

    it('should return false for primitives', () => {
      expect(isObject(null)).toBe(false);
      expect(isObject(undefined)).toBe(false);
      expect(isObject('string')).toBe(false);
      expect(isObject(123)).toBe(false);
      expect(isObject(true)).toBe(false);
    });

    it('should return false for class instances', () => {
      expect(isObject(new Date())).toBe(false);
      expect(isObject(new Map())).toBe(false);
      expect(isObject(new Set())).toBe(false);
    });
  });

  describe('assertObject', () => {
    it('should not throw for valid objects', () => {
      expect(() => assertObject({})).not.toThrow();
      expect(() => assertObject({ a: 1 })).not.toThrow();
    });

    it('should throw for non-objects', () => {
      expect(() => assertObject(null)).toThrow(InvariantError);
      expect(() => assertObject([])).toThrow(InvariantError);
      expect(() => assertObject('string')).toThrow(InvariantError);
    });

    it('should use custom message', () => {
      expect(() => assertObject(null, 'Custom error')).toThrow('Custom error');
    });
  });

  describe('getProperty', () => {
    const obj = {
      user: {
        name: 'John',
        age: 30,
        address: {
          city: 'NYC',
          zip: '10001',
        },
      },
      items: [1, 2, 3],
    };

    it('should get nested property', () => {
      expect(getProperty(obj, 'user.name')).toBe('John');
      expect(getProperty(obj, 'user.age')).toBe(30);
      expect(getProperty(obj, 'user.address.city')).toBe('NYC');
    });

    it('should throw for falsy values by default', () => {
      const objWithNull = { value: null };
      expect(() => getProperty(objWithNull, 'value')).toThrow(InvariantError);
    });

    it('should allow falsy values when configured', () => {
      const objWithNull = { value: null };
      expect(getProperty(objWithNull, 'value', true)).toBeNull();
    });

    it('should handle array access', () => {
      expect(getProperty(obj, 'items.0', true)).toBe(1);
    });
  });

  describe('objectHasOwnProperty', () => {
    it('should return true for own properties', () => {
      const obj = { a: 1, b: 2 };
      expect(objectHasOwnProperty(obj, 'a')).toBe(true);
      expect(objectHasOwnProperty(obj, 'b')).toBe(true);
    });

    it('should return false for non-existent properties', () => {
      const obj = { a: 1 };
      expect(objectHasOwnProperty(obj, 'b')).toBe(false);
    });

    it('should return false for inherited properties', () => {
      const obj = { a: 1 };
      expect(objectHasOwnProperty(obj, 'toString')).toBe(false);
    });
  });

  describe('setProperty', () => {
    it('should set a property value', () => {
      const obj = { a: 1 };
      setProperty(obj, 'a', 2);
      expect(obj.a).toBe(2);
    });

    it('should set nested property', () => {
      const obj = { user: { name: 'John' } };
      setProperty(obj, 'user.name', 'Jane');
      expect(obj.user.name).toBe('Jane');
    });

    it('should create nested path if not exists', () => {
      const obj: Record<string, unknown> = {};
      setProperty(obj, 'user.name' as never, 'John');
      expect((obj.user as Record<string, unknown>).name).toBe('John');
    });
  });

  describe('setProperties', () => {
    it('should set multiple properties', () => {
      const obj = { a: 1, b: 2 };
      setProperties(obj, { a: 10, b: 20 } as never);
      expect(obj).toEqual({ a: 10, b: 20 });
    });
  });

  describe('assertValues', () => {
    it('should not throw for valid object with truthy values', () => {
      const obj = { a: 1, b: 'test', c: true };
      expect(() => assertValues(obj)).not.toThrow();
    });

    it('should throw for object with falsy values', () => {
      const obj = { a: 1, b: null };
      expect(() => assertValues(obj)).toThrow(InvariantError);
    });

    it('should throw for non-object', () => {
      expect(() => assertValues('not an object' as never)).toThrow(
        InvariantError,
      );
    });
  });

  describe('requireAll', () => {
    it('should return object if all values are truthy', () => {
      const obj = { a: 1, b: 'test' };
      expect(requireAll(obj)).toEqual(obj);
    });

    it('should throw if any value is falsy', () => {
      expect(() => requireAll({ a: 1, b: null })).toThrow(InvariantError);
      expect(() => requireAll({ a: undefined, b: 2 })).toThrow(InvariantError);
    });
  });

