      expect(result).toEqual({
        1: { id: 1, name: 'Alice' },
        2: { id: 2, name: 'Bob' },
        3: { id: 3, name: 'Charlie' },
      });
    });

    it('should key by function', () => {
      const result = keyBy(items, item => item.name);
      expect(result).toEqual({
        Alice: { id: 1, name: 'Alice' },
        Bob: { id: 2, name: 'Bob' },
        Charlie: { id: 3, name: 'Charlie' },
      });
    });

    it('should call onDuplicate for duplicate keys', () => {
