import { describe, expect, it, vi } from 'vitest';
import {
  createErrorList,
  hasCaptureStackTrace,
  invariant,
  InvariantError,
  isErrorLike,
  moveStackTrace,
  parseInvariantMessage,
  tryCatch,
} from '../error-utils';

describe('error-utils', () => {
  describe('isErrorLike', () => {
    it('should return true for Error objects', () => {
      expect(isErrorLike(new Error('test'))).toBe(true);
    });

    it('should return true for objects with message and stack', () => {
      expect(isErrorLike({ message: 'test', stack: 'at test' })).toBe(true);
    });

    it('should return false for null', () => {
      expect(isErrorLike(null)).toBe(false);
    });

    it('should return false for undefined', () => {
      expect(isErrorLike(undefined)).toBe(false);
    });

    it('should return false for objects without stack', () => {
      expect(isErrorLike({ message: 'test' })).toBe(false);
    });

    it('should return false for objects without message', () => {
      expect(isErrorLike({ stack: 'at test' })).toBe(false);
    });

    it('should return false for primitives', () => {
      expect(isErrorLike('error')).toBe(false);
      expect(isErrorLike(123)).toBe(false);
      expect(isErrorLike(true)).toBe(false);
    });
  });

  describe('hasCaptureStackTrace', () => {
    it('should be a boolean', () => {
      expect(typeof hasCaptureStackTrace).toBe('boolean');
    });
  });

  describe('parseInvariantMessage', () => {
    it('should return string message as-is', () => {
      expect(parseInvariantMessage('test message', undefined)).toBe(
        'test message',
      );
    });

    it('should extract message from object', () => {
      expect(
        parseInvariantMessage({ message: 'object message', stack: '' }, undefined),
      ).toBe('object message');
    });

    it('should call function with type name', () => {
      const fn = (typeName: string) => `Invalid ${typeName}`;
      expect(parseInvariantMessage(fn, 'test')).toBe('Invalid String');
    });

    it('should return default message for undefined', () => {
      expect(parseInvariantMessage(undefined, undefined)).toBe(
        'Expected value to be defined.',
      );
    });
  });

  describe('InvariantError', () => {
    it('should create error with string message', () => {
      const error = new InvariantError('test error', () => {});
      expect(error.message).toBe('test error');
      expect(error).toBeInstanceOf(Error);
    });

    it('should create error with function message', () => {
      const error = new InvariantError(
        (type) => `Invalid ${type}`,
        () => {},
        'test value',
      );
      expect(error.message).toBe('Invalid String');
    });

    it('should preserve stack from message object', () => {
      const customStack = 'custom stack trace';
      const error = new InvariantError(
        { message: 'test', stack: customStack },
        () => {},
      );
      expect(error.stack).toBe(customStack);
    });
  });

  describe('invariant', () => {
    it('should not throw for truthy values', () => {
      expect(() => invariant(true)).not.toThrow();
      expect(() => invariant(1)).not.toThrow();
      expect(() => invariant('string')).not.toThrow();
      expect(() => invariant({})).not.toThrow();
      expect(() => invariant([])).not.toThrow();
    });

    it('should throw for falsy values', () => {
      expect(() => invariant(false)).toThrow(InvariantError);
      expect(() => invariant(0)).toThrow(InvariantError);
      expect(() => invariant('')).toThrow(InvariantError);
      expect(() => invariant(null)).toThrow(InvariantError);
      expect(() => invariant(undefined)).toThrow(InvariantError);
    });

    it('should use custom message', () => {
      expect(() => invariant(false, 'Custom error')).toThrow('Custom error');
    });

    it('should use message function', () => {
      expect(() =>
        invariant(null, (type) => `Expected value, got ${type}`),
      ).toThrow('Expected value, got Null');
    });

    it('should work as type guard', () => {
      const value: string | null = 'test';
      invariant(value);
      // After invariant, TypeScript knows value is truthy
      expect(value.toUpperCase()).toBe('TEST');
    });
  });

  describe('tryCatch', () => {
    it('should return success tuple for successful execution', () => {
      const [error, result] = tryCatch(() => 42);
      expect(error).toBeUndefined();
      expect(result).toBe(42);
    });

    it('should return error tuple for thrown error', () => {
      const [error, result] = tryCatch(() => {
        throw new Error('test error');
      });
      expect(error).toBeInstanceOf(Error);
      expect(error?.message).toBe('test error');
      expect(result).toBeUndefined();
    });

    it('should rethrow non-error-like values', () => {
      expect(() =>
        tryCatch(() => {
          throw 'string error';
        }),
      ).toThrow('string error');
    });

    it('should handle complex return values', () => {
      const [error, result] = tryCatch(() => ({ data: [1, 2, 3] }));
      expect(error).toBeUndefined();
      expect(result).toEqual({ data: [1, 2, 3] });
    });
  });

  describe('moveStackTrace', () => {
    it('should return error with modified stack', () => {
      const error = new Error('test');
      function targetFn() {}
      const result = moveStackTrace(error, targetFn);
      expect(result).toBe(error);
    });

    it('should wrap function and catch errors', () => {
      function targetFn() {}
      expect(() =>
        moveStackTrace(() => {
          throw new Error('wrapped error');
        }, targetFn),
      ).toThrow('wrapped error');
    });

    it('should return value from successful function', () => {
      function targetFn() {}
      const result = moveStackTrace(() => 42, targetFn);
      expect(result).toBe(42);
    });

    it('should rethrow non-error-like values from function', () => {
      function targetFn() {}
      expect(() =>
        moveStackTrace(() => {
          throw 'string';
        }, targetFn),
      ).toThrow('string');
    });
  });

  describe('createErrorList', () => {
    it('should create error collector', () => {
      const errorList = createErrorList();
      expect(errorList).toHaveProperty('add');
      expect(errorList).toHaveProperty('check');
      expect(errorList).toHaveProperty('getError');
    });

    it('should not throw when no errors added', () => {
      const errorList = createErrorList();
      expect(() => errorList.check()).not.toThrow();
    });

    it('should throw when errors are added', () => {
      const errorList = createErrorList();
      errorList.add('Error 1');
      expect(() => errorList.check()).toThrow(InvariantError);
    });

    it('should combine multiple errors', () => {
      const errorList = createErrorList();
      errorList.add('Error 1');
      errorList.add('Error 2');
      expect(() => errorList.check()).toThrow(/Error 1.*Error 2/);
    });

    it('should use custom prefix', () => {
      const errorList = createErrorList('Validation failed: ');
      errorList.add('invalid field');
      expect(() => errorList.check()).toThrow('Validation failed: invalid field');
    });

    it('should deduplicate errors', () => {
      const errorList = createErrorList();
      errorList.add('Same error');
      errorList.add('Same error');
      expect(() => errorList.check()).toThrow(/Same error/);
      // Should only contain the error once (Set behavior)
    });
  });
});
